import { useEffect, useState, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';

function ProfilePage() {
  const { user, setUser } = useAuth();
  const [name, setName] = useState(user?.name || '');
  const [bio, setBio] = useState(user?.bio || '');
  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [profileMessage, setProfileMessage] = useState('');
  const [passwordMessage, setPasswordMessage] = useState('');
  const [error, setError] = useState('');
  const [loadingProfile, setLoadingProfile] = useState(false);
  const [loadingPassword, setLoadingPassword] = useState(false);
  const [profilePic, setProfilePic] = useState(null);
  const [profilePicPreview, setProfilePicPreview] = useState(null);
  const fileInputRef = useRef(null);

  useEffect(() => {
    if (user) {
      setName(user.name || '');
      setBio(user.bio || '');
    }
  }, [user]);

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setProfilePic(file);
      const reader = new FileReader();
      reader.onload = (e) => setProfilePicPreview(e.target.result);
      reader.readAsDataURL(file);
    }
  };

  const handleRemovePhoto = () => {
    setProfilePic(null);
    setProfilePicPreview(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  const handleProfileSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setProfileMessage('');
    setLoadingProfile(true);

    try {
      const formData = new FormData();
      formData.append('name', name);
      formData.append('bio', bio);
      if (profilePic) {
        formData.append('profilePic', profilePic);
      }

      const { data } = await API.put('/auth/profile', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });
      setUser(data);
      setProfileMessage('Profile updated successfully. Na-update ang profile mo.');
      setProfilePic(null);
      setProfilePicPreview(null);
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    } catch (err) {
      setError(err?.response?.data?.message || 'Unable to update profile.');
    } finally {
      setLoadingProfile(false);
    }
  };

  const handlePasswordSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setPasswordMessage('');
    setLoadingPassword(true);

    try {
      await API.put('/auth/change-password', {
        currentPassword,
        newPassword,
      });
      setPasswordMessage('Password changed successfully. Bagong password na.');
      setCurrentPassword('');
      setNewPassword('');
    } catch (err) {
      setError(err?.response?.data?.message || 'Unable to change password.');
    } finally {
      setLoadingPassword(false);
    }
  };

  return (
    <main className="profile-page">
      <section className="profile-hero">
        <h2>Profile Page</h2>
        <p>
          I-update ang iyong profile at settings dito. This section gives you control over your name,
          bio, and account password.
        </p>
      </section>

      <section className="profile-summary">
        <h3>Account Overview</h3>
        <div className="profile-picture-section">
          <h4>Profile Picture</h4>
          <div className="profile-picture-display">
            <img
              src={
                profilePicPreview ||
                (user?.profile_pic ? `http://localhost:5000/uploads/${user.profile_pic}` : '/default-avatar.png')
              }
              alt="Profile"
              className="profile-picture"
            />
          </div>
        </div>
        <p>
          <strong>Email:</strong> {user?.email}
        </p>
        <p>
          <strong>Role:</strong> {user?.role}
        </p>
        <p>
          <strong>Status:</strong> {user?.status || 'active'}
        </p>
      </section>

      {error && <p className="error-text">{error}</p>}
      {profileMessage && <p className="success-text">{profileMessage}</p>}
      {passwordMessage && <p className="success-text">{passwordMessage}</p>}

      <section className="profile-edit">
        <h3>Edit Profile / I-update ang Profile</h3>
        <form onSubmit={handleProfileSubmit}>
          <label htmlFor="name">Name</label>
          <input
            id="name"
            value={name}
            onChange={(e) => setName(e.target.value)}
            required
          />

          <label htmlFor="bio">Bio</label>
          <textarea
            id="bio"
            rows="4"
            value={bio}
            onChange={(e) => setBio(e.target.value)}
            placeholder="Ilagay ang maikling bio mo dito"
          />

          <button type="submit" disabled={loadingProfile}>
            {loadingProfile ? 'Updating...' : 'Update Profile'}
          </button>
        </form>
      </section>

      <section className="profile-password">
        <h3>Change Password / Palitan ang Password</h3>
        <form onSubmit={handlePasswordSubmit}>
          <label htmlFor="currentPassword">Current Password</label>
          <input
            id="currentPassword"
            type="password"
            value={currentPassword}
            onChange={(e) => setCurrentPassword(e.target.value)}
            required
          />

          <label htmlFor="newPassword">New Password</label>
          <input
            id="newPassword"
            type="password"
            value={newPassword}
            onChange={(e) => setNewPassword(e.target.value)}
            required
          />

          <button type="submit" disabled={loadingPassword}>
            {loadingPassword ? 'Saving...' : 'Change Password'}
          </button>
        </form>
      </section>
    </main>
  );
}

export default ProfilePage;
